MAGIC = b"GSS1"
MAX_DGRAM = 65507
DEFAULT_BIND = "0.0.0.0"
DEFAULT_PORT = 27015

# Protocol:
# Client -> Server:
#   MAGIC (4) | msg_type (1) | flags (1) | req_id (4) | payload (0..)
# msg_type:
#   0x01 = STATUS_REQUEST
# flags:
#   bit0: 1 = client supports chunking (recommended)
#   bit1: 1 = client supports zlib compression
#
# Server -> Client:
#   MAGIC (4) | msg_type (1) | flags (1) | req_id (4) | payload...
# msg_type:
#   0x81 = STATUS_RESPONSE_SINGLE
#   0x82 = STATUS_RESPONSE_CHUNK
# flags:
#   bit0: chunked
#   bit1: compressed (zlib)
#
# Single payload:
#   json_bytes
#
# Chunked payload:
#   total_len (4) | chunk_off (4) | chunk_len (2) | chunk_bytes
#
# Notes:
# - Server may choose to chunk regardless of client flags to support large responses.
# - Server may compress if client supports it and response is large enough.

MSG_STATUS_REQ = 0x01
MSG_STATUS_RESP_SINGLE = 0x81
MSG_STATUS_RESP_CHUNK = 0x82

FLAG_CHUNKED = 1 << 0
FLAG_COMPRESSED = 1 << 1


def u32(n: int) -> bytes:
    return int(n & 0xFFFFFFFF).to_bytes(4, "big", signed=False)


def u16(n: int) -> bytes:
    return int(n & 0xFFFF).to_bytes(2, "big", signed=False)


def ru32(b: bytes) -> int:
    return int.from_bytes(b, "big", signed=False)


